Below is a simplified n8n workflow JSON snippet demonstrating how to create a reusable sub-workflow for BrightData-based web searches. This sub-workflow can be plugged into any main workflow requiring search functionality:

{
  "name": "BrightData Web Search Sub-Workflow",
  "nodes": [
    {
      "parameters": {
        "url": "={{$json.searchQuery}}",
        "options": {
          "useGoogleAI": true,
          "snapshot": true
        }
      },
      "name": "BrightData Search Node",
      "type": "n8n-nodes-base.brightData",
      "typeVersion": 1,
      "position": [250, 300]
    },
    {
      "parameters": {
        "functionCode": "return items[0].json.results"
      },
      "name": "Process Search Results",
      "type": "n8n-nodes-base.function",
      "position": [450, 300]
    }
  ],
  "connections": {
    "BrightData Search Node": {
      "main": [[{"node": "Process Search Results", "type": "main", "index": 0}]]
    }
  }
}
